onClick:
{{
(() => {

  if (!InputNewPassword.text.trim()) {
    showAlert("Podaj nowe hasło.", "warning");
    return;
  }

  resetUserPassword.run(

    () => {

      closeModal("ModalResetHasla");

      resetWidget("InputNewPassword", true);

      storeValue("editUser", null);

      showAlert(
        "Hasło zostało zmienione.",
        "success"
      );

    },

    (error) => {

      showAlert(
        "Błąd podczas zmiany hasła.",
        "error"
      );

      console.error(error);

    }

  );

})();
}}
